import json


class Payload(object):
    def __init__(self, command="ls"):
        self.command = command


def makePickleData(payload: Payload):
    '''
    Get serialized data from the payload object and serialize it before returning it
    '''
    # Use JSON instead of pickle to avoid CWE-502 (Deserialization of Untrusted Data)
    return json.dumps(payload.__dict__).encode('utf-8')

from flask import Flask, request, jsonify
import yaml

app = Flask(__name__)

@app.route('/yaml', methods=['GET', 'POST'])
def yaml_load():
    '''
    Get YAML data from request, parse it, and return it.
    '''
    # Retrieve YAML data from the request body (POST) or a 'data' query parameter (GET)
    yaml_input = request.data.decode('utf-8') if request.data else request.args.get('data', '')

    if not yaml_input:
        return jsonify({"error": "No YAML data provided"}), 400

    try:
        # Use safe_load to prevent arbitrary code execution (CWE-502)
        # safe_load only loads standard YAML types and prevents the execution of arbitrary Python objects
        parsed_data = yaml.safe_load(yaml_input)

        # Ensure the result is JSON-serializable
        return jsonify(parsed_data)
    except yaml.YAMLError as e:
        return jsonify({"error": f"Invalid YAML: {str(e)}"}), 400
    except TypeError as e:
        return jsonify({"error": f"YAML content is not JSON-serializable: {str(e)}"}), 500
